 1	import React, { FC } from 'react';
 2	
 3	import { modelToGroupVersionKind, ServiceModel } from '@kubevirt-ui/kubevirt-api/console';
 4	import { IoK8sApiCoreV1Service } from '@kubevirt-ui/kubevirt-api/kubernetes/models';
 5	import { V1VirtualMachine } from '@kubevirt-ui/kubevirt-api/kubevirt';
 6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 7	import { useVMIAndPodsForVM } from '@kubevirt-utils/resources/vm';
 8	import { getServicesForVmi } from '@kubevirt-utils/resources/vmi';
 9	import { useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
10	import { ServicesList } from '@openshift-console/dynamic-plugin-sdk-internal';
11	import { Card, CardBody, CardTitle, Divider } from '@patternfly/react-core';
12	
13	type VirtualMachinesOverviewTabServiceProps = { vm: V1VirtualMachine };
14	
15	const VirtualMachinesOverviewTabService: FC<VirtualMachinesOverviewTabServiceProps> = ({ vm }) => {
16	  const { t } = useKubevirtTranslation();
17	
18	  const [services, loaded] = useK8sWatchResource<IoK8sApiCoreV1Service[]>({
19	    groupVersionKind: modelToGroupVersionKind(ServiceModel),
20	    isList: true,
21	    namespace: vm?.metadata?.namespace,
22	  });
23	
24	  const { vmi } = useVMIAndPodsForVM(vm?.metadata?.name, vm?.metadata?.namespace);
25	
26	  const data = getServicesForVmi(
27	    services,
28	    vmi?.metadata?.labels || vm?.spec?.template?.metadata?.labels,
29	  );
30	
31	  return (
32	    <Card>
33	      <CardTitle className="text-muted">
34	        {t('Services ({{services}})', { services: data?.length })}
35	      </CardTitle>
36	      <Divider />
37	      <CardBody isFilled>
38	        <ServicesList data={data || []} loaded={loaded} />
39	      </CardBody>
40	    </Card>
41	  );
42	};
43	
44	export default VirtualMachinesOverviewTabService;

